// === src/pages/Home.js ===
import React from 'react';
import { Link } from 'react-router-dom';
import './Home.css';
import Slider from 'react-slick';
import 'slick-carousel/slick/slick.css';
import 'slick-carousel/slick/slick-theme.css';

const categories = [
  { name: 'Plants', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/Air-Purifying-Plants.jpg' },
  { name: 'Seeds', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/seeds_homepage.jpg' },
  { name: 'Pots', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/ceramic_pots_homepage.jpg' },
  { name: 'Flowers', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/flowering_plants_homepage.jpg' },
  { name: 'Decor', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/files/plant_decor_homepage.jpg' },
];

const Home = () => {
  return (
    <div className="home-container">
    <section className="carousel-section">
  <Slider
    autoplay
    autoplaySpeed={3000}
    dots={true}
    infinite={true}
    speed={500}
    slidesToShow={1}
    slidesToScroll={1}
  >
    <div><img src="https://cdn.pixabay.com/photo/2023/04/30/10/05/philodendron-7960228_1280.jpg" alt="Slide 1" /></div>
    <div><img src="https://media.istockphoto.com/id/1344395447/photo/garden.jpg?s=1024x1024&w=is&k=20&c=GOmr8xZZeJF0ZAkpmBLT2f6H0AtT_r7hcDN-tyxbY5w=" alt="Slide 2" /></div>
    <div><img src="https://www.ugaoo.com/cdn/shop/collections/Indoor-Plants-Category-Banner_1.png?v=1744446979&width=2000" alt="Slide 3" /></div>
  </Slider>
</section>


      <section className="category-section">
        <h2>Explore by Category</h2>
        <div className="category-grid">
          {categories.map((cat, idx) => (
            <Link to={`/shop?category=${cat.name}`} className="category-card" key={idx}>
              <img src={cat.image} alt={cat.name} />
              <p>{cat.name}</p>
            </Link>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Home;
